using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public RecipeService()
    {
        _recipes =
        [
            new Recipe
            {
                Id = 1,
                Title = "Classic Margherita Pizza",
                Category = "Italian",
                Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
                Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out the dough on a floured surface.\n3. Spread crushed tomatoes evenly over the dough.\n4. Tear mozzarella into pieces and distribute over the sauce.\n5. Bake for 10-12 minutes until the crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
                Ratings = [5, 4, 5, 4, 5]
            },
            new Recipe
            {
                Id = 2,
                Title = "Spaghetti Carbonara",
                Category = "Italian",
                Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper",
                Steps = "1. Cook spaghetti in salted boiling water until al dente.\n2. Crisp the guanciale in a pan over medium heat.\n3. Whisk eggs with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale, then remove from heat.\n5. Stir in the egg mixture quickly to create a creamy sauce.\n6. Serve immediately with extra cheese and pepper.",
                Ratings = [5, 5, 4]
            },
            new Recipe
            {
                Id = 3,
                Title = "Chicken Tikka Masala",
                Category = "Indian",
                Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nCrushed tomatoes\nHeavy cream\nGarlic\nGinger\nOnion",
                Steps = "1. Marinate chicken in yogurt and spices for at least 1 hour.\n2. Grill or broil chicken until charred and cooked through.\n3. Sauté onion, garlic, and ginger until softened.\n4. Add crushed tomatoes and simmer for 15 minutes.\n5. Stir in cream and add the cooked chicken.\n6. Simmer for 10 minutes and serve with rice or naan.",
                Ratings = [5, 4, 4, 5]
            },
            new Recipe
            {
                Id = 4,
                Title = "Vegetable Pad Thai",
                Category = "Thai",
                Ingredients = "Rice noodles\nTofu\nBean sprouts\nGreen onions\nPeanuts\nLime\nTamarind paste\nFish sauce\nSugar\nGarlic",
                Steps = "1. Soak rice noodles in warm water for 20 minutes, then drain.\n2. Press and cube tofu, then pan-fry until golden.\n3. Mix tamarind paste, fish sauce, and sugar for the sauce.\n4. Stir-fry garlic, then add noodles and sauce.\n5. Toss with tofu, bean sprouts, and green onions.\n6. Serve topped with crushed peanuts and a lime wedge.",
                Ratings = [4, 3, 5]
            },
            new Recipe
            {
                Id = 5,
                Title = "Beef Tacos",
                Category = "Mexican",
                Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
                Steps = "1. Brown ground beef in a skillet over medium-high heat.\n2. Add taco seasoning and water, simmer until thickened.\n3. Warm tortillas in a dry pan or microwave.\n4. Assemble tacos with beef, lettuce, tomato, and cheese.\n5. Top with sour cream and salsa.\n6. Serve with lime wedges.",
                Ratings = [4, 4, 5, 4]
            },
            new Recipe
            {
                Id = 6,
                Title = "Chocolate Lava Cake",
                Category = "Desserts",
                Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
                Steps = "1. Preheat oven to 425°F (220°C) and grease ramekins.\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick and pale.\n4. Fold chocolate mixture into the eggs, then add flour.\n5. Pour into ramekins and bake for 12-14 minutes.\n6. Invert onto plates and serve immediately.",
                Ratings = [5, 5, 5, 4, 5]
            },
            new Recipe
            {
                Id = 7,
                Title = "Guacamole",
                Category = "Mexican",
                Ingredients = "Avocados\nLime juice\nRed onion\nCilantro\nJalapeño\nTomato\nSalt\nGarlic",
                Steps = "1. Halve and pit the avocados, scoop into a bowl.\n2. Mash with a fork to desired consistency.\n3. Stir in diced onion, tomato, jalapeño, and cilantro.\n4. Add lime juice, garlic, and salt to taste.\n5. Serve immediately with tortilla chips.",
                Ratings = [4, 5, 4]
            },
            new Recipe
            {
                Id = 8,
                Title = "Miso Soup",
                Category = "Japanese",
                Ingredients = "Dashi stock\nMiso paste\nTofu\nWakame seaweed\nGreen onions",
                Steps = "1. Bring dashi stock to a gentle simmer.\n2. Dissolve miso paste into the stock (do not boil).\n3. Add cubed tofu and rehydrated wakame.\n4. Heat through for 2 minutes.\n5. Serve garnished with sliced green onions.",
                Ratings = [4, 4, 3, 4]
            }
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int rating)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && rating is >= 1 and <= 5)
        {
            recipe.Ratings.Add(rating);
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

