@page "/category/{CategoryName}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services

<PageTitle>@CategoryName Recipes</PageTitle>

<h1>@CategoryName Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>@RenderStars(recipe.AverageRating) (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] public required RecipeService RecipeService { get; set; }

    private IReadOnlyList<Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

@page "/recipe/{RecipeId:int}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services

<PageTitle>@(Recipe?.Title ?? "Recipe Not Found")</PageTitle>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@Recipe.Category">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <h3 class="mt-4">Ingredients</h3>
    <ul class="list-group list-group-flush mb-3">
        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <div class="mb-4">
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <p>@step</p>
        }
    </div>

    <h3>Rate This Recipe</h3>
    <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />
}

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] public required RecipeService RecipeService { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(RecipeId);
    }
}

@using RecipeCommunity.Services

<div class="d-flex align-items-center gap-2">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link fs-3 p-0 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                disabled="@Submitted"
                title="Rate @star star(s)">
            @(star <= (HoverStar ?? SelectedStar) ? "★" : "☆")
        </button>
    }

    @if (Submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
</div>

<p class="text-muted mt-1">
    @if (CurrentRecipe is not null && CurrentRecipe.RatingCount > 0)
    {
        <span>Average: @CurrentRecipe.AverageRating.ToString("F1") / 5 (@CurrentRecipe.RatingCount ratings)</span>
    }
    else
    {
        <span>Be the first to rate!</span>
    }
</p>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] public required RecipeService RecipeService { get; set; }

    private int SelectedStar;
    private int? HoverStar;
    private bool Submitted;
    private Models.Recipe? CurrentRecipe;

    protected override void OnParametersSet()
    {
        CurrentRecipe = RecipeService.GetById(RecipeId);
    }

    private void SubmitRating(int star)
    {
        SelectedStar = star;
        RecipeService.AddRating(RecipeId, star);
        CurrentRecipe = RecipeService.GetById(RecipeId);
        Submitted = true;
    }
}

@page "/submit"
@using RecipeCommunity.Services
@rendermode InteractiveServer

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (SubmittedRecipeId.HasValue)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong>
        <a href="recipe/@SubmittedRecipeId">View your recipe</a>
    </div>
}

<EditForm Model="FormModel" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="FormModel.Title" />
        <ValidationMessage For="() => FormModel.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="FormModel.Category">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Thai">Thai</option>
            <option value="Mexican">Mexican</option>
            <option value="Japanese">Japanese</option>
            <option value="Desserts">Desserts</option>
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => FormModel.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="FormModel.Ingredients" />
        <ValidationMessage For="() => FormModel.Ingredients" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="FormModel.Steps" />
        <ValidationMessage For="() => FormModel.Steps" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    [Inject] public required RecipeService RecipeService { get; set; }

    private RecipeFormModel FormModel { get; set; } = new();
    private int? SubmittedRecipeId { get; set; }

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(
            FormModel.Title,
            FormModel.Category,
            FormModel.Ingredients,
            FormModel.Steps);

        SubmittedRecipeId = recipe.Id;
        FormModel = new RecipeFormModel();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

