toolArgs.file_text:
@page "/submit"
@using RecipeCommunity.Services
@rendermode InteractiveServer

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (SubmittedRecipeId.HasValue)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong>
        <a href="recipe/@SubmittedRecipeId">View your recipe</a>
    </div>
}

<EditForm Model="FormModel" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="FormModel.Title" />
        <ValidationMessage For="() => FormModel.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="FormModel.Category">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Thai">Thai</option>
            <option value="Mexican">Mexican</option>
            <option value="Japanese">Japanese</option>
            <option value="Desserts">Desserts</option>
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => FormModel.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="FormModel.Ingredients" />
        <ValidationMessage For="() => FormModel.Ingredients" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="FormModel.Steps" />
        <ValidationMessage For="() => FormModel.Steps" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    [Inject] public required RecipeService RecipeService { get; set; }

    private RecipeFormModel FormModel { get; set; } = new();
    private int? SubmittedRecipeId { get; set; }

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(
            FormModel.Title,
            FormModel.Category,
            FormModel.Ingredients,
            FormModel.Steps);

        SubmittedRecipeId = recipe.Id;
        FormModel = new RecipeFormModel();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

